INSERT INTO `comments` VALUES (1,2,1,'Sangat membantu informasinya, kebetulan saya sedang diteror juga. Terima kasih tipsnya!','approved','2026-05-12 09:02:41','2026-05-12 09:02:41'),(2,4,2,'Tips yang sangat berguna, terutama bagian mengamankan kontak darurat. Terima kasih PinjolWatch!','approved','2026-05-12 09:02:41','2026-05-12 09:02:41'),(3,5,3,'Relate banget sama ceritanya, saya juga pernah merasakan hal yang sama. Rasanya sesak sekali kalau HP bunyi terus.','approved','2026-05-12 09:02:41','2026-05-12 09:03:26'),(4,4,1,'Apakah DC benar-benar akan datang ke rumah ya? Soalnya saya diancam terus mau didatangi kalau tidak bayar sore ini.','approved','2026-05-12 09:02:41','2026-05-12 09:03:28'),(5,2,2,'Komentar ini hanya untuk testing sistem moderasi admin. Semoga sistemnya lancar jaya!','approved','2026-05-12 09:02:41','2026-05-12 09:09:20'),(6,5,2,'Iklan pinjol gacor langsung cair cek link ini: bit.ly/pinjol-abal-abal','rejected','2026-05-12 09:02:41','2026-05-12 09:02:41'),(7,6,1,'Halo Bapak Budi, saya Fiona dari tim PinjolWatch. Tetap tenang ya Pak. Kami siap mendampingi proses pelaporan Bapak agar teror DC ini segera berakhir. Pastikan simpan semua bukti chatnya.','approved','2026-05-12 09:13:15','2026-05-12 09:13:15');
/*!40000 ALTER TABLE `comments` ENABLE KEYS */;
UNLOCK TABLES;

