DROP TABLE IF EXISTS `legal_pinjols`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `legal_pinjols` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `company_name` varchar(255) NOT NULL,
  `app_name` varchar(255) NOT NULL,
  `license_number` varchar(255) DEFAULT NULL,
  `license_date` date DEFAULT NULL,
  `business_type` varchar(255) DEFAULT NULL,
  `website` varchar(255) DEFAULT NULL,
  `os` varchar(255) DEFAULT NULL,
  `address` text DEFAULT NULL,
  `phone` varchar(255) DEFAULT NULL,
  `collection_patterns` text DEFAULT NULL,
  `notable_cases` text DEFAULT NULL,
  `news_links` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`news_links`)),
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=95 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

