INSERT INTO `messages` VALUES (1,NULL,6,2,'Halo admin, saya mau tanya cara lapor pinjol yang sebar data gimana ya? Saya sudah stres banget.',NULL,'2026-05-12 09:04:46','2026-05-12 09:13:15'),(2,NULL,6,4,'Selamat sore admin PinjolWatch. Apakah ada layanan bantuan hukum gratis atau LBH yang bisa mendampingi kasus saya?',NULL,'2026-05-12 09:04:46','2026-05-12 09:13:15'),(3,NULL,6,5,'TOLONG ADMIN! DC sudah mulai telepon ke kantor saya dan atasan saya marah besar. Saya bingung harus gimana lagi.',NULL,'2026-05-12 09:04:46','2026-05-12 09:13:15'),(4,NULL,2,6,'Halo Pak Budi, tetap tenang ya. Kami sarankan segera kumpulkan bukti screenshot sebar datanya untuk dilaporkan ke OJK dan Polisi.','2026-05-12 08:34:46','2026-05-12 09:04:46','2026-05-12 09:13:15'),(5,NULL,2,3,'Jika Anda mendapatkan ancaman/teror dari DC lapangan:\n1. Tetap tenang dan jangan panik.\n2. Rekam seluruh interaksi (chat/telepon/video).\n3. Minta bukti identitas, sertifikat SPPI, dan surat tugas.\n4. Jika ada kekerasan fisik/ancaman nyawa, segera lapor polisi (110).\nAnda bisa membaca panduan lengkapnya di menu \'Cerita Kita\' pada portal kami.',NULL,'2026-05-12 09:05:59','2026-05-12 09:05:59'),(6,NULL,4,3,'Halo, untuk melaporkan pinjol ilegal, Anda bisa menghubungi Satgas PASTI OJK melalui:\n1. WhatsApp: 081-157-157-157\n2. Email: konsumen@ojk.go.id\n3. Telepon: 157\nPastikan Anda sudah menyiapkan bukti berupa screenshot aplikasi dan ancaman yang diterima.',NULL,'2026-05-12 09:06:22','2026-05-12 09:06:22'),(7,NULL,5,3,'Kami memahami situasi ini sangat berat bagi kesehatan mental Anda. Jika Anda merasa sangat tertekan, silakan hubungi layanan bantuan psikologis darurat di:\n- Healing 119 (Ext. 8)\n- Atau kunjungi komunitas pemulihan kami di menu \'Healing\' untuk berbagi dengan sesama penyintas.',NULL,'2026-05-12 09:06:40','2026-05-12 09:06:40'),(8,NULL,6,3,'Halo, untuk melaporkan pinjol ilegal, Anda bisa menghubungi Satgas PASTI OJK melalui:\n1. WhatsApp: 081-157-157-157\n2. Email: konsumen@ojk.go.id\n3. Telepon: 157\nPastikan Anda sudah menyiapkan bukti berupa screenshot aplikasi dan ancaman yang diterima.',NULL,'2026-05-12 09:15:01','2026-05-12 09:15:01'),(9,NULL,6,6,'tes',NULL,'2026-05-12 16:20:57','2026-05-12 16:20:57');
/*!40000 ALTER TABLE `messages` ENABLE KEYS */;
UNLOCK TABLES;

