INSERT INTO `recovery_stages` VALUES (1,'Fase Kesadaran & Keamanan','awareness-safety','Langkah pertama untuk berhenti meminjam dan mengamankan diri dari teror.',1,'shield-check','[\"Ganti nomor HP atau matikan izin aplikasi\",\"Beritahu kontak darurat\\/keluarga tentang situasi sebenarnya\",\"Hapus semua aplikasi pinjol ilegal dari ponsel\",\"Buat laporan pertama di PinjolWatch\"]','2026-05-12 17:39:24','2026-05-12 17:39:24'),(2,'Fase Inventarisasi & Pembersihan','cleanup-inventory','Mendata semua utang dan memilah mana yang legal dan ilegal.',2,'clipboard-list','[\"List semua aplikasi, nominal pokok, dan bunga\",\"Identifikasi mana yang terdaftar OJK dan mana yang tidak\",\"Cek skor SLIK OJK (khusus pinjol legal)\",\"Siapkan draf negosiasi untuk pinjol legal\"]','2026-05-12 17:39:25','2026-05-12 17:39:25'),(3,'Fase Stabilitas Mental','mental-stability','Fokus pada kesehatan mental dan tidak lagi merasa bersalah/malu.',3,'heart-pulse','[\"Konsultasi dengan psikolog atau teman terpercaya\",\"Mulai rutin berolahraga\\/meditasi untuk kurangi kecemasan\",\"Berhenti mengecek media sosial penagih\\/forum pinjol yang toxic\",\"Ikuti komunitas penyintas untuk saling menguatkan\"]','2026-05-12 17:39:25','2026-05-12 17:39:25'),(4,'Fase Pemberdayaan Ekonomi','economic-empowerment','Membangun kembali keuangan dan masa depan tanpa utang.',4,'trending-up','[\"Mulai menabung dana darurat minimal 500rb\",\"Cari penghasilan tambahan (side hustle)\",\"Edukasi diri tentang literasi keuangan dasar\",\"Menjadi mentor\\/berbagi cerita untuk membantu korban lain\"]','2026-05-12 17:39:25','2026-05-12 17:39:25');
/*!40000 ALTER TABLE `recovery_stages` ENABLE KEYS */;
UNLOCK TABLES;

